import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import {
  Box,
  Button,
  CircularProgress,
  Paper,
  TextField,
  Typography,
  Alert,
} from "@mui/material";

export default function Register() {
  const [form, setForm] = useState({ name: "", phone: "", email: "" });
  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState({ type: "", text: "" });
  const navigate = useNavigate();

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const submit = async (e) => {
    e.preventDefault();
    setMsg({ type: "", text: "" });

    try {
      setLoading(true);
      // 🔗 Change base URL if your backend runs elsewhere
      await axios.post("http://localhost:5000/api/users/register", form);

      setMsg({ type: "success", text: "✅ Registered successfully! Redirecting..." });
      setTimeout(() => navigate("/login"), 1200);
    } catch (err) {
      setMsg({
        type: "error",
        text: err?.response?.data?.message || "❌ Registration failed",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      display="flex"
      justifyContent="center"
      alignItems="center"
      minHeight="100vh"
      sx={{ bgcolor: "#f5f5f5", p: 2 }}
    >
      <Paper elevation={4} sx={{ p: 4, maxWidth: 420, width: "100%" }}>
        <Typography variant="h5" align="center" gutterBottom>
          Create an Account
        </Typography>

        <Box component="form" onSubmit={submit} noValidate>
          <TextField
            label="Full Name"
            name="name"
            value={form.name}
            onChange={handleChange}
            fullWidth
            margin="normal"
            required
          />

          <TextField
            label="Phone Number"
            name="phone"
            value={form.phone}
            onChange={handleChange}
            fullWidth
            margin="normal"
            required
            type="tel"
          />

          <TextField
            label="Email Address"
            name="email"
            value={form.email}
            onChange={handleChange}
            fullWidth
            margin="normal"
            type="email"
            required
          />

          <Box mt={3} position="relative">
            <Button
              type="submit"
              variant="contained"
              color="primary"
              fullWidth
              disabled={loading}
            >
              {loading ? "Registering..." : "Register"}
            </Button>
            {loading && (
              <CircularProgress
                size={24}
                sx={{
                  position: "absolute",
                  top: "50%",
                  left: "50%",
                  mt: "-12px",
                  ml: "-12px",
                }}
              />
            )}
          </Box>
        </Box>

        {msg.text && (
          <Box mt={2}>
            <Alert severity={msg.type}>{msg.text}</Alert>
          </Box>
        )}
      </Paper>
    </Box>
  );
}
